#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *A = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &A[i]);
        int answer = 2000000000; // large
        for (int i = 0; i < N; ++i) {
            int best = 0;
            if (i > 0) {
                int diff = abs(A[i] - A[i-1]);
                if (diff > best) best = diff;
            }
            if (i + 1 < N) {
                int diff = abs(A[i] - A[i+1]);
                if (diff > best) best = diff;
            }
            if (best < answer) answer = best;
        }
        printf("%d\n", answer);
        free(A);
    }
    return 0;
}

