#!/usr/bin/env python3
import sys

def solve():
    data = list(map(int, sys.stdin.read().strip().split()))
    if not data:
        return
    it = iter(data)
    T = next(it)
    out_lines = []
    for _ in range(T):
        N = next(it)
        A = [next(it) for _ in range(N)]
        ans = 10**9
        for i in range(N):
            cur = 0
            if i > 0:
                cur = max(cur, abs(A[i] - A[i-1]))
            if i + 1 < N:
                cur = max(cur, abs(A[i] - A[i+1]))
            if cur < ans:
                ans = cur
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

